import Foundation

// Type safety prevents implicit conversions
let apples = 5
let pricePerApple = 0.75

// Must convert explicitly
let totalCost = Double(apples) * pricePerApple
print("Total: $\(totalCost)")

// String conversion
let count = 42
let message = "The answer is " + String(count)
print(message)

// Truncation when converting Double to Int
let pi = 3.14159
let truncatedPi = Int(pi)
print("Truncated pi: \(truncatedPi)")  // 3
